import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppState {
  START = 'START',
  CAMERA = 'CAMERA',
  PROCESSING = 'PROCESSING',
  RESULT = 'RESULT',
  ERROR = 'ERROR'
}

export interface GeneratedImage {
  imageUrl: string;
  timestamp: number;
}

import { GoogleGenAI } from "@google/genai";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateMarathonImage = async (base64InputImage: string): Promise<string> => {
  try {
    // Strip the data URL prefix if present to get raw base64
    const base64Data = base64InputImage.replace(/^data:image\/(png|jpeg|jpg);base64,/, '');

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `
              Transform this selfie into a high-quality, professional photograph of a marathon runner participating in the Tata Mumbai Marathon.

              Key Requirements:
              1. Keep the person's face clearly recognizable but make them look fit, sweaty, and energetic as if they are running.
              2. The person should be wearing a professional marathon running jersey. The jersey should have "IDFC FIRST Bank" branding visible if possible, or use colors maroon and white.
              3. The background should be the iconic Bandra-Worli Sea Link bridge in Mumbai during a bright, sunny morning with other blurred runners in the background to show depth.
              4. The style should be realistic, inspiring, and heroic.
              5. Ensure the lighting is natural and dynamic.
            `,
          },
        ],
      },
    });

    // Extract the generated image from the response
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

