import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera, RefreshCw, AlertCircle } from 'lucide-react';

interface CameraCaptureProps {
  onCapture: (imageSrc: string) => void;
  onBack: () => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture, onBack }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);

  const startCamera = useCallback(async () => {
    try {
      setError(null);
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } },
        audio: false,
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      setError("Unable to access camera. Please allow permissions.");
      console.error(err);
    }
  }, []);

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
    };
  }, [startCamera, stopCamera]);

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        // Match canvas size to video size
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;

        // Flip horizontally for mirror effect natural feel
        context.translate(canvas.width, 0);
        context.scale(-1, 1);

        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        const imageSrc = canvas.toDataURL('image/jpeg', 0.9);
        stopCamera();
        onCapture(imageSrc);
      }
    }
  };

  return (
    <div className="flex flex-col h-screen bg-black text-white">
      {/* Header */}
      <div className="p-4 flex justify-between items-center bg-gradient-to-b from-black/70 to-transparent z-10 absolute top-0 w-full">
        <button onClick={onBack} className="text-sm font-medium hover:text-gray-300">
          Cancel
        </button>
        <span className="font-semibold tracking-wide">Take a Selfie</span>
        <div className="w-10"></div> {/* Spacer */}
      </div>

      {/* Camera Viewport */}
      <div className="flex-1 relative bg-gray-900 flex items-center justify-center overflow-hidden">
        {error ? (
           <div className="text-center p-6">
             <AlertCircle className="mx-auto mb-4 text-red-500" size={48} />
             <p className="text-lg font-medium">{error}</p>
             <button onClick={startCamera} className="mt-4 px-4 py-2 bg-red-700 rounded-lg">Retry</button>
           </div>
        ) : (
            <>
                <video
                    ref={videoRef}
                    autoPlay
                    playsInline
                    muted
                    className="absolute w-full h-full object-cover transform -scale-x-100"
                />
                {/* Overlay Guide Frame */}
                <div className="absolute border-2 border-white/30 rounded-full w-64 h-80 top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>
                <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-white/50 font-medium mt-48 text-sm">
                    Position your face here
                </div>
            </>
        )}
        <canvas ref={canvasRef} className="hidden" />
      </div>

      {/* Controls */}
      <div className="p-8 bg-black flex justify-center items-center relative">
         <button
            onClick={captureImage}
            disabled={!!error}
            className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center hover:bg-white/10 transition active:scale-95"
         >
             <div className="w-16 h-16 bg-red-600 rounded-full"></div>
         </button>

         <div className="absolute right-8 top-1/2 transform -translate-y-1/2 text-xs text-gray-500 text-center">
            <Camera className="mx-auto mb-1" size={20} />
            <span>Photo</span>
         </div>
      </div>
    </div>
  );
};

