import React, { useState } from 'react';
import { AppState } from './types';
import { StartScreen } from './components/StartScreen';
import { CameraCapture } from './components/CameraCapture';
import { ProcessingScreen } from './components/ProcessingScreen';
import { ResultScreen } from './components/ResultScreen';
import { generateMarathonImage } from './services/geminiService';
import { AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.START);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const handleStart = () => {
    setErrorMessage(null);
    setAppState(AppState.CAMERA);
  };

  const handleCapture = async (imageSrc: string) => {
    setAppState(AppState.PROCESSING);
    try {
      const resultImage = await generateMarathonImage(imageSrc);
      setGeneratedImage(resultImage);
      setAppState(AppState.RESULT);
    } catch (error: any) {
      console.error("Generation failed", error);
      setErrorMessage(error?.message || "Failed to generate image. Please try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRestart = () => {
    setGeneratedImage(null);
    setErrorMessage(null);
    setAppState(AppState.START);
  };

  const handleErrorRetry = () => {
     setAppState(AppState.CAMERA);
  };

  return (
    <div className="min-h-screen w-full bg-gray-50">
      {appState === AppState.START && (
        <StartScreen onStart={handleStart} />
      )}

      {appState === AppState.CAMERA && (
        <CameraCapture 
          onCapture={handleCapture} 
          onBack={() => setAppState(AppState.START)} 
        />
      )}

      {appState === AppState.PROCESSING && (
        <ProcessingScreen />
      )}

      {appState === AppState.RESULT && generatedImage && (
        <ResultScreen 
          imageSrc={generatedImage} 
          onRestart={handleRestart} 
        />
      )}

      {appState === AppState.ERROR && (
        <div className="flex flex-col items-center justify-center h-screen bg-white p-6 text-center">
            <div className="bg-red-50 p-6 rounded-full mb-6">
                <AlertTriangle className="text-red-600" size={48} />
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Oops! Something went wrong.</h2>
            <p className="text-gray-600 mb-8 max-w-md">{errorMessage}</p>
            <div className="flex gap-4">
                 <button 
                    onClick={handleRestart}
                    className="px-6 py-3 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50"
                 >
                    Back to Home
                 </button>
                 <button 
                    onClick={handleErrorRetry}
                    className="px-6 py-3 bg-red-800 text-white rounded-lg font-medium hover:bg-red-900"
                 >
                    Try Again
                 </button>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;

