          aspectRatio: { ideal: 1.777 } // Prefer 16:9 source
        },
        audio: false,
      });

      streamRef.current = mediaStream;

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      setError("Unable to access camera. Please allow permissions.");
      console.error(err);
    }
  }, []);

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
    };
  }, [startCamera, stopCamera]);

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        // We want to capture a 9:16 Portrait crop from the video feed
        const videoW = video.videoWidth;
        const videoH = video.videoHeight;
        const videoAspect = videoW / videoH;
        const targetAspect = 9 / 16;

        let sourceX = 0;
        let sourceY = 0;
        let sourceW = videoW;
        let sourceH = videoH;

        if (videoAspect > targetAspect) {
          // Video is wider than target (Landscape input -> Portrait output)
          // Crop the width (sides)
          sourceH = videoH;
          sourceW = videoH * targetAspect;
          sourceX = (videoW - sourceW) / 2;
        } else {
          // Video is taller than target (Rare for webcam, but possible)
          // Crop the height
          sourceW = videoW;
          sourceH = videoW / targetAspect;
          sourceY = (videoH - sourceH) / 2;
        }

        // Set canvas to the cropped dimensions
        canvas.width = sourceW;
        canvas.height = sourceH;

        // Flip horizontally for mirror effect
        context.translate(canvas.width, 0);
        context.scale(-1, 1);

        // Draw the cropped area
        context.drawImage(
          video, 
          sourceX, sourceY, sourceW, sourceH, // Source crop
          0, 0, canvas.width, canvas.height   // Destination (full canvas)
        );

        const imageSrc = canvas.toDataURL('image/jpeg', 0.9);
        stopCamera();
        onCapture(imageSrc);
      }
    }
  };

  return (
    <div className="flex flex-col h-screen bg-black text-white">
      {/* Header */}
      <div className="p-4 flex justify-between items-center bg-black z-10">
        <button onClick={onBack} className="p-2 rounded-full hover:bg-gray-800 transition-colors">
          <ArrowLeft size={24} />
        </button>
        <span className="font-semibold tracking-wide text-lg">Selfie</span>
        <div className="w-10"></div> {/* Spacer */}
      </div>

      {/* Main Content Area - Centered Portrait Frame */}
      <div className="flex-1 flex flex-col items-center justify-center p-4 bg-gray-900 relative">
        {error ? (
           <div className="text-center p-6 max-w-xs bg-gray-800 rounded-xl">
             <AlertCircle className="mx-auto mb-4 text-red-500" size={48} />
             <p className="text-lg font-medium mb-2">Camera Error</p>
             <p className="text-sm text-gray-400 mb-4">{error}</p>
             <button onClick={startCamera} className="px-4 py-2 bg-red-700 text-white rounded-lg hover:bg-red-800">Retry</button>
           </div>
        ) : (
          <div className="relative w-full max-w-[400px] aspect-[9/16] bg-black rounded-3xl overflow-hidden shadow-2xl border-4 border-gray-800 ring-4 ring-black">

            {/* Video Feed */}
            <video
              ref={videoRef}
              autoPlay
              playsInline
              muted
              className="w-full h-full object-cover transform scale-x-[-1]"
            />

            {/* Guide Overlay inside the frame */}
            <div className="absolute inset-0 pointer-events-none">
                <div className="absolute top-1/4 left-1/2 transform -translate-x-1/2 w-48 h-64 border-2 border-white/20 rounded-[50%] border-dashed"></div>
                <div className="absolute bottom-8 w-full text-center text-white/70 text-sm font-medium px-4">
                  Keep face within frame
                </div>
            </div>

            {/* Flash Effect on Capture (Optional enhancement could go here) */}
          </div>
        )}
        <canvas ref={canvasRef} className="hidden" />
      </div>

      {/* Footer Controls */}
      <div className="p-8 bg-black flex justify-around items-center">
         <div className="w-12"></div> {/* Spacer to balance layout */}

         <button
            onClick={captureImage}
            disabled={!!error}
            className="group relative w-20 h-20 flex items-center justify-center"
         >
            <div className="absolute inset-0 rounded-full border-4 border-white opacity-100 group-hover:scale-105 transition-transform duration-200"></div>
            <div className="w-16 h-16 bg-idfc-maroon rounded-full group-active:scale-90 transition-transform duration-100 shadow-[0_0_15px_rgba(158,42,43,0.5)]"></div>
         </button>

         <div className="w-12 flex justify-center">
            {/* Optional: Switch Camera Button could go here */}
            {/* <button className="p-2 rounded-full bg-gray-800 text-white">
                <RefreshCw size={20} />
            </button> */}
         </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppState } from './types';
import { StartScreen } from './components/StartScreen';
import { CameraCapture } from './components/CameraCapture';
import { ProcessingScreen } from './components/ProcessingScreen';
import { ResultScreen } from './components/ResultScreen';
import { generateMarathonImage } from './services/geminiService';
import { AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.START);
  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const handleStart = () => {
    setErrorMessage(null);
    setAppState(AppState.CAMERA);
  };

  const handleCapture = async (imageSrc: string) => {
    setSourceImage(imageSrc); // Store the original selfie
    setAppState(AppState.PROCESSING);

    try {
      const resultImage = await generateMarathonImage(imageSrc);
      setGeneratedImage(resultImage);
      setAppState(AppState.RESULT);
    } catch (error: any) {
      console.error("Generation failed", error);
      setErrorMessage(error?.message || "Failed to generate image. Please try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRegenerate = async () => {
    if (!sourceImage) return;

    setAppState(AppState.PROCESSING);
    try {
      const resultImage = await generateMarathonImage(sourceImage);
      setGeneratedImage(resultImage);
      setAppState(AppState.RESULT);
    } catch (error: any) {
      console.error("Regeneration failed", error);
      setErrorMessage(error?.message || "Failed to regenerate image.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRestart = () => {
    setGeneratedImage(null);
    setSourceImage(null);
    setErrorMessage(null);
    setAppState(AppState.START);
  };

  const handleErrorRetry = () => {
     setAppState(AppState.CAMERA);
  };

  return (
    <div className="min-h-screen w-full bg-gray-50 font-inter">
      {appState === AppState.START && (
        <StartScreen onStart={handleStart} />
      )}

      {appState === AppState.CAMERA && (
        <CameraCapture 
          onCapture={handleCapture} 
          onBack={() => setAppState(AppState.START)} 
        />
      )}

      {appState === AppState.PROCESSING && (
        <ProcessingScreen />
      )}

      {appState === AppState.RESULT && generatedImage && (
        <ResultScreen 
          imageSrc={generatedImage} 
          onRestart={handleRestart}
          onRegenerate={handleRegenerate}
        />
      )}

      {appState === AppState.ERROR && (
        <div className="flex flex-col items-center justify-center h-screen bg-white p-6 text-center">
            <div className="bg-red-50 p-6 rounded-full mb-6">
                <AlertTriangle className="text-red-600" size={48} />
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Oops! Something went wrong.</h2>
            <p className="text-gray-600 mb-8 max-w-md">{errorMessage}</p>
            <div className="flex gap-4">
                 <button 
                    onClick={handleRestart}
                    className="px-6 py-3 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50"
                 >
                    Back to Home
                 </button>
                 <button 
                    onClick={handleErrorRetry}
                    className="px-6 py-3 bg-idfc-maroon text-white rounded-lg font-medium hover:bg-idfc-dark"
                 >
                    Try Again
                 </button>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera, AlertCircle, ArrowLeft, RotateCcw, Check, Sparkles } from 'lucide-react';

interface CameraCaptureProps {
  onCapture: (imageSrc: string) => void;
  onBack: () => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture, onBack }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const [error, setError] = useState<string | null>(null);
  const [countdown, setCountdown] = useState<number | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  const startCamera = useCallback(async () => {
    try {
      setError(null);
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }

      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { 
          facingMode: 'user', 
          width: { ideal: 1280 }, 
          height: { ideal: 720 },
          aspectRatio: { ideal: 1.777 }
        },
        audio: false,
      });

      streamRef.current = mediaStream;

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      setError("Unable to access camera. Please allow permissions.");
      console.error(err);
    }
  }, []);

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  useEffect(() => {
    // Only start camera if we don't have a captured image
    if (!capturedImage) {
      startCamera();
    }
    return () => stopCamera();
  }, [capturedImage, startCamera, stopCamera]);

  // Countdown Logic
  useEffect(() => {
    if (countdown === null) return;

    if (countdown > 0) {
      const timer = setTimeout(() => {
        setCountdown(countdown - 1);
      }, 1000);
      return () => clearTimeout(timer);
    } else {
      // Countdown finished, capture!
      performCapture();
      setCountdown(null);
    }
  }, [countdown]);

  const initiateCapture = () => {
    setCountdown(3);
  };

  const performCapture = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        // Crop logic 9:16
        const videoW = video.videoWidth;
        const videoH = video.videoHeight;
        const videoAspect = videoW / videoH;
        const targetAspect = 9 / 16;

        let sourceX = 0;
        let sourceY = 0;
        let sourceW = videoW;
        let sourceH = videoH;

        if (videoAspect > targetAspect) {
          sourceH = videoH;
          sourceW = videoH * targetAspect;
          sourceX = (videoW - sourceW) / 2;
        } else {
          sourceW = videoW;
          sourceH = videoW / targetAspect;
          sourceY = (videoH - sourceH) / 2;
        }

        canvas.width = sourceW;
        canvas.height = sourceH;

        context.translate(canvas.width, 0);
        context.scale(-1, 1);

        context.drawImage(
          video, 
          sourceX, sourceY, sourceW, sourceH, 
          0, 0, canvas.width, canvas.height
        );

        const imageSrc = canvas.toDataURL('image/jpeg', 0.95);
        stopCamera();
        setCapturedImage(imageSrc);
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    // startCamera will trigger via useEffect
  };

  const handleConfirm = () => {
    if (capturedImage) {
      onCapture(capturedImage);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gradient-to-br from-red-900 to-red-700 text-white relative overflow-hidden">

      {/* Decorative Background for Marathon Vibe */}
      <div className="absolute inset-0 opacity-20 pointer-events-none">
         <div className="absolute top-10 right-0 w-64 h-64 bg-yellow-500 blur-[100px] rounded-full mix-blend-overlay animate-pulse"></div>
         <div className="absolute bottom-10 left-0 w-80 h-80 bg-red-500 blur-[80px] rounded-full mix-blend-multiply"></div>
         <svg className="w-full h-full opacity-30" viewBox="0 0 100 100" preserveAspectRatio="none">
             <line x1="0" y1="100" x2="100" y2="0" stroke="white" strokeWidth="0.5" strokeDasharray="5,5" />
             <line x1="20" y1="100" x2="100" y2="20" stroke="white" strokeWidth="0.5" strokeDasharray="5,5" />
         </svg>
      </div>

      {/* Header */}
      <div className="p-4 flex justify-between items-center z-10">
        <button onClick={onBack} className="p-2 rounded-full hover:bg-white/10 transition-colors backdrop-blur-md">
          <ArrowLeft size={24} />
        </button>
        <span className="font-bold tracking-widest uppercase text-sm drop-shadow-md">
            {capturedImage ? "Review Photo" : "Selfie Camera"}
        </span>
        <div className="w-10"></div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col items-center justify-center p-4 relative z-10">
        {error ? (
           <div className="text-center p-6 max-w-xs bg-white/10 backdrop-blur-md rounded-xl border border-white/20">
             <AlertCircle className="mx-auto mb-4 text-red-300" size={48} />
             <p className="text-lg font-medium mb-2">Camera Error</p>
             <p className="text-sm text-gray-200 mb-4">{error}</p>
             <button onClick={startCamera} className="px-4 py-2 bg-white text-red-900 font-bold rounded-lg">Retry</button>
           </div>
        ) : (
          <div className="relative w-full max-w-[400px] aspect-[9/16] bg-black rounded-3xl overflow-hidden shadow-2xl border-4 border-white/20 ring-1 ring-black/50">

            {capturedImage ? (
                <img src={capturedImage} alt="Preview" className="w-full h-full object-cover" />
            ) : (
                <video
                    ref={videoRef}
                    autoPlay
                    playsInline
                    muted
                    className="w-full h-full object-cover transform scale-x-[-1]"
                />
            )}

            {/* Countdown Overlay */}
            {countdown !== null && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-20">
                    <div className="text-9xl font-black text-white drop-shadow-[0_0_20px_rgba(255,255,255,0.8)] animate-bounce">
                        {countdown}
                    </div>
                </div>
            )}
          </div>
        )}
        <canvas ref={canvasRef} className="hidden" />
      </div>

      {/* Footer Controls */}
      <div className="p-8 pb-12 z-10">
         {capturedImage ? (
             <div className="flex items-center justify-center gap-6">
                 <button 
                    onClick={handleRetake}
                    className="flex flex-col items-center gap-2 text-sm font-medium text-gray-300 hover:text-white transition-colors"
                 >
                     <div className="w-14 h-14 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/20 hover:bg-white/20">
                        <RotateCcw size={24} />
                     </div>
                     <span>Retake</span>
                 </button>

                 <button 
                    onClick={handleConfirm}
                    className="flex flex-col items-center gap-2 text-sm font-bold text-white group"
                 >
                     <div className="w-20 h-20 rounded-full bg-yellow-400 text-red-900 flex items-center justify-center shadow-[0_0_30px_rgba(250,204,21,0.4)] group-hover:scale-105 transition-transform">
                        <Sparkles size={32} />
                     </div>
                     <span className="text-yellow-400">Generate AI</span>
                 </button>
             </div>
         ) : (
             <div className="flex justify-center items-center">
                <button
                    onClick={initiateCapture}
                    disabled={!!error || countdown !== null}
                    className="group relative w-24 h-24 flex items-center justify-center"
                >
                    <div className="absolute inset-0 rounded-full border-4 border-white opacity-50 group-hover:scale-110 transition-transform duration-300"></div>
                    <div className="absolute inset-2 rounded-full border-2 border-white opacity-100"></div>
                    <div className="w-16 h-16 bg-white rounded-full group-active:scale-95 transition-transform duration-100 shadow-[0_0_20px_rgba(255,255,255,0.5)]"></div>
                    <div className="absolute -bottom-8 text-xs font-semibold tracking-wider opacity-80 uppercase">Tap to Snap</div>
                </button>
             </div>
         )}
      </div>
    </div>
  );
};

